print "Location: $redirect_url\n\n";

sub validate_and_sanitize_redirect {
    my ($url) = @_;
    
    my $default_url = '/dashboard';
    
    return $default_url unless defined $url && $url ne '';
    
    $url =~ s/^\s+|\s+$//g;
    
    return $default_url if $url =~ /^https?:\/\//i;
    
    return $default_url if $url =~ /^\/\//;
    
    return $default_url if $url =~ /[\r\n]/;
    
    return $default_url if $url =~ /^[^\/]/;
    
    return $default_url if $url =~ /\.\./;
    
    return $default_url if $url =~ /^javascript:/i;
    
    return $default_url if $url =~ /^data:/i;
    
    return $default_url if $url =~ /^vbscript:/i;
    
    return $default_url if length($url) > 500;
    
    unless ($url =~ /^\/[a-zA-Z0-9\/_\-\.?&=]*$/) {
        return $default_url;
    }
    
    return $url;
